"use client";

import { useMemo, useCallback } from "react";
import type { MotionValue } from "framer-motion";

import type { UseCylinderTransformReturn, CylinderTransform } from "../types";
import { getCircularDistance, calculateCylinderTransform, DEFAULT_CYLINDER_CONFIG } from "../utils/math";

interface CylinderConfig {
  itemHeight: number;
  cylinderRadius: number;
  visibleItems: number;
  maxRotateX: number;
  maxScale: number;
  minScale: number;
  maxOpacity: number;
  minOpacity: number;
  maxBlur: number;
}

export function useCylinderTransform(
  itemHeight: number,
  visibleItems: number,
  loop: boolean,
  customConfig?: Partial<CylinderConfig>
): UseCylinderTransformReturn {
  const cylinderRadius = itemHeight / 0.342;

  const config: CylinderConfig = useMemo(
    () => ({
      itemHeight,
      cylinderRadius,
      visibleItems,
      ...DEFAULT_CYLINDER_CONFIG,
      ...customConfig,
    }),
    [itemHeight, cylinderRadius, visibleItems, customConfig]
  );

  const getTransform = useCallback(
    (index: number, _centerIndex: number, smoothIndex: number): CylinderTransform => {
      const distance = getCircularDistance(index, smoothIndex, 1000, loop);
      return calculateCylinderTransform(distance, config);
    },
    [config, loop]
  );

  return { getTransform };
}

export function useItemTransform(
  index: number,
  smoothIndex: MotionValue<number>,
  config: CylinderConfig,
  loop: boolean
): {
  translateY: ReturnType<typeof import("framer-motion").useTransform>;
  rotateX: ReturnType<typeof import("framer-motion").useTransform>;
  scale: ReturnType<typeof import("framer-motion").useTransform>;
  opacity: ReturnType<typeof import("framer-motion").useTransform>;
  blur: ReturnType<typeof import("framer-motion").useTransform>;
  zIndex: ReturnType<typeof import("framer-motion").useTransform>;
} {
  const { useTransform } = require("framer-motion");

  const d = useTransform(smoothIndex, (latestY: number) => {
    let diff = index - latestY;
    if (loop) {
      const half = 1000 / 2;
      diff = ((diff + half) % 1000 + 1000) % 1000 - half;
    }
    return diff;
  });

  const translateY = useTransform(d, (diff: number) => diff * config.itemHeight);
  const rotateX = useTransform(d, (diff: number) => {
    const normalized = Math.min(Math.abs(diff) / (config.visibleItems / 2), 1);
    return -diff * config.maxRotateX * normalized;
  });
  const scale = useTransform(d, (diff: number) => {
    const normalized = Math.min(Math.abs(diff) / (config.visibleItems / 2), 1);
    return 1 - normalized * (1 - config.minScale);
  });
  const opacity = useTransform(d, (diff: number) => {
    const normalized = Math.min(Math.abs(diff) / (config.visibleItems / 2), 1);
    return config.maxOpacity - normalized * (config.maxOpacity - config.minOpacity);
  });
  const blur = useTransform(d, (diff: number) => {
    const normalized = Math.min(Math.abs(diff) / (config.visibleItems / 2), 1);
    return config.maxBlur * normalized;
  });
  const zIndex = useTransform(d, (diff: number) => {
    return Math.floor(config.visibleItems * 2 - Math.abs(diff));
  });

  return { translateY, rotateX, scale, opacity, blur, zIndex };
}

"use client";

import { useCallback } from "react";

import type { UseInfiniteLoopReturn, WheelItem } from "../types";

export function useInfiniteLoop(
  items: WheelItem[],
  _currentIndex: number,
  _visibleItems: number
): UseInfiniteLoopReturn {
  const totalItems = items.length;

  const adjustIndex = useCallback(
    (index: number): number => {
      if (totalItems === 0) return 0;
      return ((index % totalItems) + totalItems) % totalItems;
    },
    [totalItems]
  );

  const getLoopIndices = useCallback(
    (centerIndex: number, count: number): number[] => {
      if (totalItems === 0) return [];

      const half = Math.floor(count / 2);
      const indices: number[] = [];

      for (let i = -half; i <= half; i++) {
        const idx = adjustIndex(centerIndex + i);
        indices.push(idx);
      }

      return indices;
    },
    [totalItems, adjustIndex]
  );

  return {
    adjustIndex,
    getLoopIndices,
    totalItems,
  };
}

export function createInfiniteItems<T extends WheelItem>(
  items: T[],
  repeatCount: number = 3
): T[] {
  if (items.length === 0) return [];

  const result: T[] = [];
  for (let i = 0; i < repeatCount; i++) {
    items.forEach((item, index) => {
      result.push({
        ...item,
        value: `${item.value}__${i}_${index}`,
      } as T);
    });
  }
  return result;
}

export function getInfiniteIndex(
  index: number,
  originalLength: number,
  repeatCount: number = 3
): number {
  if (originalLength === 0) return 0;
  const totalLength = originalLength * repeatCount;
  const adjusted = ((index % totalLength) + totalLength) % totalLength;
  return adjusted % originalLength;
}

export function findCenterIndex(
  totalLength: number,
  repeatCount: number = 3
): number {
  return Math.floor((totalLength * repeatCount) / 2);
}

"use client";

import { useRef, useCallback, useEffect } from "react";

import type { UseAudioReturn } from "../types";
import { playClickSoundWithVolume, playHoverSound } from "../utils/audio";

export function useAudio(): UseAudioReturn {
  const volumeRef = useRef(0.04);
  const enabledRef = useRef(true);
  const lastClickTimeRef = useRef(0);
  const lastHoverTimeRef = useRef(0);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    return () => {
      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }
    };
  }, []);

  const playClick = useCallback(
    (volume?: number) => {
      if (!enabledRef.current) return;

      const now = Date.now();
      if (now - lastClickTimeRef.current < 45) return;
      lastClickTimeRef.current = now;

      const vol = volume !== undefined ? volume : volumeRef.current;
      playClickSoundWithVolume(vol);
    },
    []
  );

  const playHover = useCallback(
    (volume?: number) => {
      if (!enabledRef.current) return;

      const now = Date.now();
      if (now - lastHoverTimeRef.current < 100) return;
      lastHoverTimeRef.current = now;

      const vol = volume !== undefined ? volume : volumeRef.current * 0.5;
      playHoverSound(vol);
    },
    []
  );

  const setVolume = useCallback((volume: number) => {
    volumeRef.current = Math.max(0, Math.min(1, volume));
  }, []);

  const setEnabled = useCallback((enabled: boolean) => {
    enabledRef.current = enabled;
  }, []);

  return {
    playClick,
    playHover,
    setVolume,
    setEnabled,
  };
}

"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import { useMotionValue, useSpring, animate } from "framer-motion";

import type {
  WheelPickerProps,
  UseWheelReturn,
  ScrollToOptions,
} from "../types";
import { playClickSound } from "../utils/audio";

export function useWheel(props: WheelPickerProps): UseWheelReturn {
  const {
    items = [],
    value,
    defaultValue,
    onChange,
    loop = false,
    sound = true,
    disabled = false,
    spring,
  } = props;

  const containerRef = useRef<HTMLDivElement>(null);
  const total = items.length;

  const isControlled = value !== undefined;
  const [localValue, setLocalValue] = useState(() => {
    const initial = isControlled ? value : (defaultValue || items[0]?.value || "");
    return initial;
  });

  const activeValue = isControlled ? value : localValue;

  const initialIndex = items.findIndex((item) => item.value === activeValue);
  const startIndex = initialIndex !== -1 ? initialIndex : 0;

  const y = useMotionValue(startIndex);
  const smoothY = useSpring(y, {
    stiffness: spring?.stiffness ?? 180,
    damping: spring?.damping ?? 24,
    mass: spring?.mass ?? 0.8,
  });

  const lastIndexRef = useRef(startIndex);
  const isDraggingRef = useRef(false);
  const isAnimatingRef = useRef(false);

  const scrollToIndex = useCallback(
    (index: number, options?: ScrollToOptions) => {
      if (disabled) return;

      let target = index;
      if (!loop) {
        target = Math.max(0, Math.min(total - 1, target));
      }

      const springConfig = options?.spring || {
        stiffness: 180,
        damping: 24,
        mass: 0.8,
      };

      isAnimatingRef.current = true;
      animate(y, target, {
        type: "spring",
        ...springConfig,
        onComplete: () => {
          isAnimatingRef.current = false;
        },
      });
    },
    [y, disabled, loop, total]
  );

  const scrollToValue = useCallback(
    (valueToFind: string, options?: ScrollToOptions) => {
      const targetIdx = items.findIndex((item) => item.value === valueToFind);
      if (targetIdx !== -1) {
        scrollToIndex(targetIdx, options);
      }
    },
    [items, scrollToIndex]
  );

  useEffect(() => {
    if (isControlled && value !== undefined) {
      const targetIdx = items.findIndex((item) => item.value === value);
      if (targetIdx !== -1 && targetIdx !== lastIndexRef.current) {
        lastIndexRef.current = targetIdx;
        scrollToIndex(targetIdx);
      }
    }
  }, [value, items, isControlled, scrollToIndex]);

  useEffect(() => {
    const unsubscribe = smoothY.on("change", (latest) => {
      const rounded = Math.round(latest);
      let activeIdx = rounded;

      if (loop) {
        activeIdx = ((rounded % total) + total) % total;
      } else {
        activeIdx = Math.max(0, Math.min(total - 1, rounded));
      }

      if (activeIdx !== lastIndexRef.current) {
        lastIndexRef.current = activeIdx;

        if (sound && !disabled && !isDraggingRef.current) {
          playClickSound();
        }

        if (!isControlled) {
          setLocalValue(items[activeIdx]?.value || "");
        }

        if (onChange) {
          onChange(items[activeIdx]?.value || "");
        }
      }
    });

    return unsubscribe;
  }, [smoothY, total, loop, sound, disabled, items, onChange, isControlled]);

  const navigateTo = useCallback(
    (index: number) => {
      scrollToIndex(index);
    },
    [scrollToIndex]
  );

  const next = useCallback(() => {
    if (disabled) return;
    scrollToIndex(lastIndexRef.current + 1);
  }, [disabled, scrollToIndex]);

  const previous = useCallback(() => {
    if (disabled) return;
    scrollToIndex(lastIndexRef.current - 1);
  }, [disabled, scrollToIndex]);

  const getCurrentIndex = useCallback(() => {
    return lastIndexRef.current;
  }, []);

  const getCurrentValue = useCallback(() => {
    return items[lastIndexRef.current]?.value || "";
  }, [items]);

  const setCurrentIndex = useCallback(
    (index: number) => {
      lastIndexRef.current = index;
      if (!isControlled) {
        setLocalValue(items[index]?.value || "");
      }
      y.set(index);
    },
    [items, isControlled, y]
  );

  const setIsDragging = useCallback((value: boolean) => {
    isDraggingRef.current = value;
  }, []);

  const setDragStartOffset = useCallback((value: number) => {
    y.set(value);
  }, [y]);

  return {
    containerRef: containerRef as React.RefObject<HTMLDivElement>,
    items,
    currentIndex: lastIndexRef.current,
    targetIndex: Math.round(y.get()),
    smoothIndex: smoothY.get(),
    isDragging: isDraggingRef.current,
    isAnimating: isAnimatingRef.current,
    dragStartOffset: y.get(),
    setIsDragging,
    setDragStartOffset,
    navigateTo,
    next,
    previous,
    scrollToValue,
    scrollToIndex,
    getCurrentIndex,
    getCurrentValue,
    setCurrentIndex,
  };
}

"use client";

import { useRef, useCallback, useEffect } from "react";
import type { MotionValue, SpringOptions } from "framer-motion";

import type { UseMomentumReturn } from "../types";
import { MOMENTUM_FRICTION, MOMENTUM_THRESHOLD, calculateMomentumTarget } from "../utils/physics";

export function useMomentum(
  position: MotionValue<number>,
  springConfig: SpringOptions = { stiffness: 120, damping: 20, mass: 0.7 }
): UseMomentumReturn {
  const velocityRef = useRef(0);
  const isDeceleratingRef = useRef(false);
  const animationFrameRef = useRef<number | null>(null);
  const lastPositionRef = useRef(position.get());
  const lastTimeRef = useRef(Date.now());

  const startMomentum = useCallback(
    (initialVelocity: number) => {
      velocityRef.current = initialVelocity;
      isDeceleratingRef.current = true;

      const animate = () => {
        if (!isDeceleratingRef.current) return;

        const currentPos = position.get();
        velocityRef.current *= MOMENTUM_FRICTION;

        if (Math.abs(velocityRef.current) < MOMENTUM_THRESHOLD) {
          isDeceleratingRef.current = false;
          const target = Math.round(calculateMomentumTarget(currentPos, velocityRef.current));
          position.set(target);
          return;
        }

        position.set(currentPos - velocityRef.current * 0.1);
        animationFrameRef.current = requestAnimationFrame(animate);
      };

      animationFrameRef.current = requestAnimationFrame(animate);
    },
    [position, springConfig]
  );

  const stopMomentum = useCallback(() => {
    isDeceleratingRef.current = false;
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
    }
  }, []);

  useEffect(() => {
    const unsubscribe = position.on("change", (latest: number) => {
      const now = Date.now();
      const dt = (now - lastTimeRef.current) / 1000;

      if (dt > 0 && dt < 0.1) {
        velocityRef.current = (latest - lastPositionRef.current) / dt;
      }

      lastPositionRef.current = latest;
      lastTimeRef.current = now;
    });

    return () => {
      unsubscribe();
      stopMomentum();
    };
  }, [position, stopMomentum]);

  return {
    velocity: velocityRef.current,
    startMomentum,
    stopMomentum,
    isDecelerating: isDeceleratingRef.current,
  };
}

export function useMomentumTracker(position: MotionValue<number>): {
  velocity: number;
  update: (newPosition: number) => void;
} {
  const velocityRef = useRef(0);
  const lastPositionRef = useRef(position.get());
  const lastTimeRef = useRef(Date.now());

  const update = useCallback((newPosition: number) => {
    const now = Date.now();
    const dt = (now - lastTimeRef.current) / 1000;

    if (dt > 0 && dt < 0.1) {
      velocityRef.current = (newPosition - lastPositionRef.current) / dt;
    }

    lastPositionRef.current = newPosition;
    lastTimeRef.current = now;
  }, []);

  return {
    velocity: velocityRef.current,
    update,
  };
}

"use client";

import { useCallback } from "react";

import type { UseSnapReturn } from "../types";
import { calculateMomentumTarget, clamp } from "../utils/physics";

export function useSnap(
  totalItems: number,
  loop: boolean,
  getCurrentPosition: () => number,
  animateFn: (target: number, springConfig?: { stiffness: number; damping: number; mass: number }) => void,
  springConfig: { stiffness: number; damping: number; mass: number }
): UseSnapReturn {
  const isSnappingRef = { current: false };

  const snapToNearest = useCallback(
    (currentIndex: number, velocity?: number): number => {
      let target: number;

      if (velocity !== undefined && Math.abs(velocity) > 0.01) {
        const currentPos = getCurrentPosition();
        const momentumTarget = calculateMomentumTarget(currentPos, velocity);
        target = Math.round(momentumTarget);
      } else {
        target = Math.round(currentIndex);
      }

      if (!loop) {
        target = clamp(target, 0, totalItems - 1);
      } else {
        target = ((target % totalItems) + totalItems) % totalItems;
      }

      if (target !== currentIndex) {
        isSnappingRef.current = true;
        animateFn(target, springConfig);

        setTimeout(() => {
          isSnappingRef.current = false;
        }, 300);
      }

      return target;
    },
    [totalItems, loop, getCurrentPosition, animateFn, springConfig]
  );

  return {
    snapToNearest,
    isSnapping: isSnappingRef.current,
  };
}

export function calculateSnapTarget(
  currentPosition: number,
  totalItems: number,
  loop: boolean,
  velocity?: number
): number {
  let target: number;

  if (velocity !== undefined && Math.abs(velocity) > 0.01) {
    target = Math.round(calculateMomentumTarget(currentPosition, velocity));
  } else {
    target = Math.round(currentPosition);
  }

  if (!loop) {
    target = clamp(target, 0, totalItems - 1);
  } else {
    target = ((target % totalItems) + totalItems) % totalItems;
  }

  return target;
}

export interface SpringConfig {
  stiffness: number;
  damping: number;
  mass: number;
}

export interface SpringState {
  position: number;
  velocity: number;
}

export const DEFAULT_SPRING_CONFIG: SpringConfig = {
  stiffness: 180,
  damping: 24,
  mass: 0.8,
};

export const MOMENTUM_SPRING_CONFIG: SpringConfig = {
  stiffness: 120,
  damping: 20,
  mass: 0.7,
};

export function calculateSpringForce(
  currentPosition: number,
  targetPosition: number,
  currentVelocity: number,
  config: SpringConfig
): number {
  const displacement = targetPosition - currentPosition;
  const springForce = -config.stiffness * displacement;
  const dampingForce = -config.damping * currentVelocity;
  return (springForce + dampingForce) / config.mass;
}

export function simulateSpringFrame(
  state: SpringState,
  target: number,
  config: SpringConfig,
  deltaTime: number
): SpringState {
  const force = calculateSpringForce(state.position, target, state.velocity, config);
  const newVelocity = state.velocity + force * deltaTime;
  const newPosition = state.position + newVelocity * deltaTime;
  return { position: newPosition, velocity: newVelocity };
}

export function calculateMomentumDecay(
  velocity: number,
  friction: number,
  deltaTime: number
): number {
  return velocity * Math.pow(friction, deltaTime * 60);
}

export function calculateStopTime(
  velocity: number,
  friction: number,
  threshold: number = 0.001
): number {
  if (velocity === 0) return 0;
  return Math.log(threshold / Math.abs(velocity)) / Math.log(friction) / 60;
}

export function easeOutCubic(t: number): number {
  return 1 - Math.pow(1 - t, 3);
}

export function easeOutQuart(t: number): number {
  return 1 - Math.pow(1 - t, 4);
}

export function easeOutExpo(t: number): number {
  return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
}

export function springTo(_target: number, config: SpringConfig = DEFAULT_SPRING_CONFIG) {
  return {
    type: "spring" as const,
    stiffness: config.stiffness,
    damping: config.damping,
    mass: config.mass,
  };
}

export const MOMENTUM_FRICTION = 0.95;
export const MOMENTUM_THRESHOLD = 0.001;
export const MOMENTUM_MULTIPLIER = 8.5;

export function calculateMomentumTarget(
  currentPosition: number,
  velocity: number,
  multiplier: number = MOMENTUM_MULTIPLIER
): number {
  return currentPosition - velocity * multiplier;
}

export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function lerp(start: number, end: number, t: number): number {
  return start + (end - start) * t;
}

export function mapRange(
  value: number,
  inMin: number,
  inMax: number,
  outMin: number,
  outMax: number
): number {
  return outMin + ((value - inMin) / (inMax - inMin)) * (outMax - outMin);
}

let audioContext: AudioContext | null = null;
let lastPlayTime = 0;
const MIN_PLAY_INTERVAL = 45;

export interface ClickSoundConfig {
  frequencyStart: number;
  frequencyEnd: number;
  duration: number;
  volume: number;
  type: OscillatorType;
}

export const DEFAULT_CLICK_CONFIG: ClickSoundConfig = {
  frequencyStart: 1400,
  frequencyEnd: 120,
  duration: 0.007,
  volume: 0.04,
  type: "sine",
};

export const SUBTLE_CLICK_CONFIG: ClickSoundConfig = {
  frequencyStart: 1200,
  frequencyEnd: 100,
  duration: 0.006,
  volume: 0.03,
  type: "sine",
};

export const MECHANICAL_CLICK_CONFIG: ClickSoundConfig = {
  frequencyStart: 1600,
  frequencyEnd: 150,
  duration: 0.008,
  volume: 0.05,
  type: "triangle",
};

export function getAudioContext(): AudioContext | null {
  if (typeof window === "undefined") return null;

  if (!audioContext) {
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContextClass) return null;
    audioContext = new AudioContextClass();
  }

  if (audioContext.state === "suspended") {
    audioContext.resume();
  }

  return audioContext;
}

export function playClickSound(config: ClickSoundConfig = DEFAULT_CLICK_CONFIG): void {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = Date.now();
  if (now - lastPlayTime < MIN_PLAY_INTERVAL) return;
  lastPlayTime = now;

  try {
    const oscillator = ctx.createOscillator();
    const gainNode = ctx.createGain();

    oscillator.type = config.type;
    oscillator.frequency.setValueAtTime(config.frequencyStart, ctx.currentTime);
    oscillator.frequency.exponentialRampToValueAtTime(
      config.frequencyEnd,
      ctx.currentTime + config.duration
    );

    gainNode.gain.setValueAtTime(config.volume, ctx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(
      0.0001,
      ctx.currentTime + config.duration
    );

    oscillator.connect(gainNode);
    gainNode.connect(ctx.destination);

    oscillator.start();
    oscillator.stop(ctx.currentTime + config.duration);
  } catch (e) {
    console.warn("Failed to play click sound:", e);
  }
}

export function playHoverSound(volume: number = 0.015): void {
  const ctx = getAudioContext();
  if (!ctx) return;

  try {
    const oscillator = ctx.createOscillator();
    const gainNode = ctx.createGain();

    oscillator.type = "sine";
    oscillator.frequency.setValueAtTime(800, ctx.currentTime);
    oscillator.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.003);

    gainNode.gain.setValueAtTime(volume, ctx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 0.003);

    oscillator.connect(gainNode);
    gainNode.connect(ctx.destination);

    oscillator.start();
    oscillator.stop(ctx.currentTime + 0.004);
  } catch (e) {
    console.warn("Failed to play hover sound:", e);
  }
}

export function playClickSoundWithVolume(volume: number): void {
  playClickSound({ ...DEFAULT_CLICK_CONFIG, volume });
}

export function createClickSound(config: ClickSoundConfig = DEFAULT_CLICK_CONFIG): () => void {
  let lastPlay = 0;
  const interval = MIN_PLAY_INTERVAL;

  return () => {
    const now = Date.now();
    if (now - lastPlay < interval) return;
    lastPlay = now;
    playClickSound(config);
  };
}

export function suspendAudio(): void {
  if (audioContext && audioContext.state === "running") {
    audioContext.suspend();
  }
}

export function resumeAudio(): void {
  if (audioContext && audioContext.state === "suspended") {
    audioContext.resume();
  }
}

export function closeAudio(): void {
  if (audioContext) {
    audioContext.close();
    audioContext = null;
  }
}

export function setClickVolume(volume: number): void {
  if (audioContext) {
    audioContext.destination.gain.value = Math.max(0, Math.min(1, volume));
  }
}

export interface CylinderTransform {
  translateY: number;
  rotateX: number;
  scale: number;
  opacity: number;
  blur: number;
  zIndex: number;
}

export interface CylinderConfig {
  itemHeight: number;
  cylinderRadius: number;
  visibleItems: number;
  maxRotateX: number;
  maxScale: number;
  minScale: number;
  maxOpacity: number;
  minOpacity: number;
  maxBlur: number;
}

export const DEFAULT_CYLINDER_CONFIG: Omit<CylinderConfig, "itemHeight" | "cylinderRadius" | "visibleItems"> = {
  maxRotateX: 35,
  maxScale: 1,
  minScale: 0.85,
  maxOpacity: 1,
  minOpacity: 0.25,
  maxBlur: 2,
};

export function calculateCylinderRadius(itemHeight: number, stepDegrees: number = 18): number {
  const stepRadians = (stepDegrees * Math.PI) / 180;
  return itemHeight / (2 * Math.sin(stepRadians / 2));
}

export function getCircularDistance(
  index: number,
  currentPosition: number,
  totalItems: number,
  loop: boolean
): number {
  let diff = index - currentPosition;
  if (loop) {
    const half = totalItems / 2;
    diff = ((diff + half) % totalItems + totalItems) % totalItems - half;
  }
  return diff;
}

export function calculateCylinderTransform(
  distance: number,
  config: CylinderConfig
): CylinderTransform {
  const absDistance = Math.abs(distance);
  const maxVisibleDistance = (config.visibleItems - 1) / 2;
  const normalizedDistance = Math.min(absDistance / maxVisibleDistance, 1);

  const direction = distance >= 0 ? 1 : -1;

  const rotateX = direction * config.maxRotateX * normalizedDistance;
  const scale = lerp(config.maxScale, config.minScale, normalizedDistance);
  const opacity = lerp(config.maxOpacity, config.minOpacity, normalizedDistance);
  const blur = config.maxBlur * normalizedDistance;
  const translateY = distance * config.itemHeight;

  const zIndex = Math.floor(config.visibleItems * 2 - absDistance);

  return {
    translateY,
    rotateX,
    scale,
    opacity,
    blur,
    zIndex,
  };
}

export function getItemTransform(
  index: number,
  scrollPosition: number,
  config: CylinderConfig,
  loop: boolean
): CylinderTransform {
  const distance = getCircularDistance(index, scrollPosition, 100, loop);
  return calculateCylinderTransform(distance, config);
}

export function getItemStyle(
  transform: CylinderTransform,
  itemHeight: number
): React.CSSProperties {
  return {
    transform: `translateY(${transform.translateY}px) rotateX(${transform.rotateX}deg) scale(${transform.scale})`,
    opacity: transform.opacity,
    filter: `blur(${transform.blur}px)`,
    zIndex: transform.zIndex,
    transformStyle: "preserve-3d" as const,
    willChange: "transform, opacity, filter",
    backfaceVisibility: "hidden" as const,
    height: `${itemHeight}px`,
    lineHeight: `${itemHeight}px`,
  };
}

function lerp(start: number, end: number, t: number): number {
  return start + (end - start) * t;
}

export function smoothStep(edge0: number, edge1: number, x: number): number {
  const t = clamp((x - edge0) / (edge1 - edge0), 0, 1);
  return t * t * (3 - 2 * t);
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function getSelectionIndicatorPosition(
  visibleItems: number,
  itemHeight: number
): number {
  return (visibleItems - 1) * itemHeight / 2;
}

export function getViewportHeight(visibleItems: number, itemHeight: number): number {
  return visibleItems * itemHeight;
}

